import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { obtenerProductos, guardarProducto } from '../services/productoService';

const Inventario = () => {
    const navigate = useNavigate();
    const [productos, setProductos] = useState([]);
    const [nuevoProd, setNuevoProd] = useState({
        codigo: '', nombre: '', stock: 0, precioCompra: 0, precioVenta: 0, categoria: 'Fundas'
    });

    // Cargamos los productos al abrir la página
    useEffect(() => {
        const user = localStorage.getItem('usuarioLogueado');
        if (!user) {
            navigate('/'); // Si no estás logueado, te regresa al login
        } else {
            cargarProductos();
        }
    }, [navigate]);

    const cargarProductos = async () => {
        const data = await obtenerProductos();
        setProductos(data);
    };

    const handleGuardar = async (e) => {
        e.preventDefault();
        // Usamos tu matrícula guardada en el login para el registro
        const autor = localStorage.getItem('usuarioLogueado');
        const productoFinal = { ...nuevoProd, registradoPorMatricula: autor };
        
        await guardarProducto(productoFinal);
        alert("Producto guardado con éxito");
        setNuevoProd({ codigo: '', nombre: '', stock: 0, precioCompra: 0, precioVenta: 0, categoria: 'Fundas' });
        cargarProductos();
    };

    const handleLogout = () => {
        localStorage.removeItem('usuarioLogueado');
        navigate('/');
    };

    return (
        <div style={{ padding: '30px', fontFamily: 'Arial' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <h1 style={{ color: '#007bff' }}>Isla Tecnológica - Inventario</h1>
                <button onClick={handleLogout} style={{ backgroundColor: '#dc3545', color: 'white', padding: '10px', borderRadius: '5px', cursor: 'pointer', border: 'none' }}>
                    Cerrar Sesión
                </button>
            </div>

            {/* Formulario de Registro */}
            <div style={{ background: '#f8f9fa', padding: '20px', borderRadius: '10px', marginBottom: '30px' }}>
                <h3>Registrar Nueva Mercancía</h3>
                <form onSubmit={handleGuardar} style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '10px' }}>
                    <input placeholder="Código (Ej: F15-01)" value={nuevoProd.codigo} onChange={e => setNuevoProd({...nuevoProd, codigo: e.target.value})} required style={{ padding: '8px' }} />
                    <input placeholder="Nombre del producto" value={nuevoProd.nombre} onChange={e => setNuevoProd({...nuevoProd, nombre: e.target.value})} required style={{ padding: '8px' }} />
                    <input type="number" placeholder="Stock inicial" value={nuevoProd.stock} onChange={e => setNuevoProd({...nuevoProd, stock: parseInt(e.target.value)})} required style={{ padding: '8px' }} />
                    <input type="number" step="0.01" placeholder="Costo Compra ($)" value={nuevoProd.precioCompra} onChange={e => setNuevoProd({...nuevoProd, precioCompra: parseFloat(e.target.value)})} required style={{ padding: '8px' }} />
                    <input type="number" step="0.01" placeholder="Precio Venta ($)" value={nuevoProd.precioVenta} onChange={e => setNuevoProd({...nuevoProd, precioVenta: parseFloat(e.target.value)})} required style={{ padding: '8px' }} />
                    <select value={nuevoProd.categoria} onChange={e => setNuevoProd({...nuevoProd, categoria: e.target.value})} style={{ padding: '8px' }}>
                        <option value="Fundas">Fundas</option>
                        <option value="Micas">Micas</option>
                        <option value="Cargadores">Cargadores</option>
                    </select>
                    <button type="submit" style={{ gridColumn: 'span 3', padding: '10px', backgroundColor: '#28a745', color: 'white', border: 'none', borderRadius: '5px', cursor: 'pointer', fontWeight: 'bold' }}>
                        Guardar en Inventario
                    </button>
                </form>
            </div>

            {/* Tabla de Resultados */}
            <table border="1" width="100%" style={{ borderCollapse: 'collapse', textAlign: 'center' }}>
                <thead style={{ backgroundColor: '#007bff', color: 'white' }}>
                    <tr>
                        <th>Código</th>
                        <th>Producto</th>
                        <th>Stock</th>
                        <th>Costo</th>
                        <th>Venta</th>
                        <th>Ganancia (u)</th>
                        <th>Categoría</th>
                    </tr>
                </thead>
                <tbody>
                    {productos.map(p => (
                        <tr key={p.id} style={{ backgroundColor: p.stock < 5 ? '#ffe6e6' : 'transparent' }}>
                            <td>{p.codigo}</td>
                            <td>{p.nombre}</td>
                            <td style={{ fontWeight: 'bold', color: p.stock < 5 ? 'red' : 'black' }}>{p.stock}</td>
                            <td>${p.precioCompra.toFixed(2)}</td>
                            <td>${p.precioVenta.toFixed(2)}</td>
                            <td style={{ color: 'green', fontWeight: 'bold' }}>
                                ${(p.precioVenta - p.precioCompra).toFixed(2)}
                            </td>
                            <td>{p.categoria}</td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
};

export default Inventario;
